static ai_handle s_network = AI_HANDLE_NULL;

static void EdgeWind_AI_PrintError(const char *stage, ai_error err)
{
  printf("AI %s failed: type=0x%02X code=0x%02X\r\n", stage, err.type, err.code);
}

static int EdgeWind_AI_RunOne(const EdgeWind_AIGoldenVector *vec, ai_buffer *input, ai_buffer *output, uint32_t *cycles_out)
{
  ai_i32 batch;
  uint32_t start_cycles;
  const float *prob;
  float max_diff = 0.0f;
  float best_prob = -1.0f;
  uint32_t best_id = 0U;

  memcpy((void *)input[0].data, vec->dwt, AI_NETWORK_IN_1_SIZE_BYTES);
  memcpy((void *)input[1].data, vec->feat, AI_NETWORK_IN_2_SIZE_BYTES);
  memcpy((void *)input[2].data, vec->spec, AI_NETWORK_IN_3_SIZE_BYTES);

  DWT->CYCCNT = 0U;
  start_cycles = DWT->CYCCNT;
  batch = ai_network_run(s_network, input, output);
  *cycles_out = DWT->CYCCNT - start_cycles;

  if (batch != 1) {
    EdgeWind_AI_PrintError("run", ai_network_get_error(s_network));
    return -1;
  }

  prob = (const float *)output[0].data;
  for (uint32_t i = 0U; i < AI_NETWORK_OUT_1_SIZE; ++i) {
    float diff = prob[i] - vec->expected[i];
    if (diff < 0.0f) {
      diff = -diff;
    }
    if (diff > max_diff) {
      max_diff = diff;
    }
    if (prob[i] > best_prob) {
      best_prob = prob[i];
      best_id = i;
    }
  }

  printf("AI golden %02lu %s/%s/%s: pred=%lu conf=%.6f expected=%lu ref=%.6f max_diff=%.8f cycles=%lu\r\n",
         (unsigned long)vec->vector_id,
         vec->class_code,
         vec->class_name,
         vec->tag,
         (unsigned long)best_id,
         (double)best_prob,
         (unsigned long)vec->expected_class,
         (double)vec->ref_confidence,
         (double)max_diff,
         (unsigned long)(*cycles_out));

  return ((best_id == vec->expected_class) && (max_diff < EDGEWIND_AI_PASS_DIFF_MAX)) ? 0 : 1;
}

int EdgeWind_AI_RunGoldenSelfTest(void)
{
  ai_handle activations[] = { (ai_handle)EDGEWIND_AI_ACTIVATION_ADDR };
  ai_error err;
  ai_buffer *input;
  ai_buffer *output;
  uint32_t pass_count = 0U;
  uint32_t fail_count = 0U;
  uint64_t total_cycles = 0ULL;
  uint32_t min_cycles = 0xFFFFFFFFU;
  uint32_t max_cycles = 0U;
  uint32_t core_hz;
  uint32_t hclk_hz;

  err = ai_network_create_and_init(&s_network, activations, NULL);
  if (err.type != AI_ERROR_NONE) {
    EdgeWind_AI_PrintError("create", err);
    return -1;
  }

  input = ai_network_inputs_get(s_network, NULL);
  output = ai_network_outputs_get(s_network, NULL);
  if ((input == NULL) || (output == NULL)) {
    printf("AI get io buffers failed\r\n");
    return -2;
  }

  CoreDebug->DEMCR |= CoreDebug_DEMCR_TRCENA_Msk;
  DWT->CTRL |= DWT_CTRL_CYCCNTENA_Msk;

  printf("AI golden batch start: vectors=%lu act=0x%08lX\r\n",
         (unsigned long)EDGEWIND_AI_VECTOR_COUNT,
         (unsigned long)EDGEWIND_AI_ACTIVATION_ADDR);

  for (uint32_t i = 0U; i < EDGEWIND_AI_VECTOR_COUNT; ++i) {
    uint32_t cycles = 0U;
    int ret = EdgeWind_AI_RunOne(&s_vectors[i], input, output, &cycles);
    if (ret == 0) {
      ++pass_count;
    } else {
      ++fail_count;
    }
    total_cycles += cycles;
    if (cycles < min_cycles) {
      min_cycles = cycles;
    }
    if (cycles > max_cycles) {
      max_cycles = cycles;
    }
  }

  SystemCoreClockUpdate();
  core_hz = SystemCoreClock;
  hclk_hz = HAL_RCC_GetHCLKFreq();
  if (core_hz >= 1000000U) {
    uint32_t cyc_per_us = core_hz / 1000000U;
    uint32_t avg_cycles = (uint32_t)(total_cycles / EDGEWIND_AI_VECTOR_COUNT);
    printf("AI golden summary: pass=%lu fail=%lu avg_us=%lu min_us=%lu max_us=%lu core=%lu hclk=%lu\r\n",
           (unsigned long)pass_count,
           (unsigned long)fail_count,
           (unsigned long)(avg_cycles / cyc_per_us),
           (unsigned long)(min_cycles / cyc_per_us),
           (unsigned long)(max_cycles / cyc_per_us),
           (unsigned long)core_hz,
           (unsigned long)hclk_hz);
  } else {
    printf("AI golden summary: pass=%lu fail=%lu avg_cycles=%lu min_cycles=%lu max_cycles=%lu core=%lu hclk=%lu\r\n",
           (unsigned long)pass_count,
           (unsigned long)fail_count,
           (unsigned long)(total_cycles / EDGEWIND_AI_VECTOR_COUNT),
           (unsigned long)min_cycles,
           (unsigned long)max_cycles,
           (unsigned long)core_hz,
           (unsigned long)hclk_hz);
  }

  return (fail_count == 0U) ? 0 : 1;
}
